(window.webpackJsonp=window.webpackJsonp||[]).push([[294],{921:function(n,t){n.exports='\x3c!-- \ntitle: 10-CSS基础\nsort: \n--\x3e \n\n# CSS基础\n\n## First\n\n![image-20200721103637737](https://gitee.com/nmdfzf404/Image-hosting/raw/master/20200721103644.png)\n\n## 基础\n\n### 选择器\n\n```css\n/* id选择器 */\n#test { }\n\n/* class选择器 */\n.test2 { }\n\n/* 属性选择器 */\n[title="test"] { }\n\n/* 子类选择器 */\n/* div下所有p */\ndiv p { }\n.a ~ div { }\n/* 父标签是div的p */\ndiv > p { }\n/* a标签下面的div */\n.a + div { }\n\n```\n\n### 创建css\n\n```html\n\x3c!-- 外链css --\x3e\n<head>\n<link rel="stylesheet" type="text/css" href="mystyle.css">\n</head>\n\n\x3c!-- 内链css --\x3e\n<style>\nhr {color:sienna;}\np {margin-left:20px;}\nbody {background-image:url("images/background.png");}\n</style>\n\n<p style="color:sienna;margin-left:20px">这是一个段落。</p>\n \n\x3c!-- 引入css文件 --\x3e\n@import url(test.css)\n```\n\n## 背景\n\n```css\nbackground-color\nbackground-image\n/* 背景图像的重复方式 */\nbackground-repeat\n\nbackground-repeat:repeat-x\t\t水平方向平铺\nbackground-repeat:no-repeat\t\t取消平铺\n/* 背景是否固定 */\nbackground-attachment\n\nbackground-position\nbackground-position:right top\t位置在右上方\n/* 简写 */\nbody {background:#ffffff url(\'img_tree.png\') no-repeat right top;}\n```\n\n## 文本\n\n```css\ncolor:red\n/* 对齐方式 */\ntext-align:cneter\ncenter\t中心\nright\t右侧\njustify 每一行宽度相等对齐\n/* 删除链接下划线 */\ntext-decoration:none\n/* 上中下线 */\nh1 {text-decoration:overline;}\nh2 {text-decoration:line-through;}\nh3 {text-decoration:underline;}\t\n/* 设置字体 */\np { font-family:"Times New Roman", Times, serif;}\n```\n\n\n## 伪类\n\n```css\na:link {color:#000000;}\t\t/* 未访问链接*/\na:visited {color:#00FF00;}\t/* 已访问链接 */\na:hover {color:#FF00FF;}\t/* 鼠标移动到链接上 */\na:active {color:#0000FF;}\t/* 鼠标点击时 */\ninput:focus {outline: none;}/* 选中集中时 */\n\np:first-letter {}\t/* 第一个单词 */\np:after {content: "text"}\t/* 末尾添加 */\n```\n\n## 列表及表格\n\n### 标记\n\n```css\nul.a {list-style-type: circle;}\nul.b {list-style-type: square;}\n \nol.c {list-style-type: upper-roman;}\nol.d {list-style-type: lower-alpha;}\n\n/* 图像标记 */\nul\n{\n    list-style-image: url(\'sqpurple.gif\');\n}\n\n/* 简写 */\nul\n{\n    list-style: square url("sqpurple.gif");\n}\n```\n\n### 表格\n\n```css\n/* 边框 */\nable, th, td\n{\n    border: 1px solid black;\n}\n\ntd\n{\n    padding:15px;\n}\n\n/* 颜色 */\ntable, td, th\n{\n    border:1px solid green;\n}\nth\n{\n    background-color:green;\n    color:white;\n}\n```\n\n'}}]);